// Transform backlink data
const input = $input.first().json;
const tasks = input.tasks || [];
const backlinks = tasks[0]?.result?.[0]?.items || [];

const now = new Date().toISOString();

const records = backlinks.map(bl => ({
  source_url: bl.url_from,
  source_domain: bl.domain_from,
  target_url: bl.url_to,
  target_path: new URL(bl.url_to).pathname,
  anchor_text: bl.anchor,
  is_dofollow: bl.dofollow,
  is_image_link: bl.is_image,
  domain_authority: bl.domain_from_rank,
  page_authority: bl.page_from_rank,
  spam_score: bl.domain_from_spam_score || 0,
  first_seen_at: bl.first_seen || now,
  last_seen_at: now,
  status: 'active'
}));

return records.map(r => ({ json: r }));
